import pandas as pd
import numpy as np
df = pd.DataFrame({'name': ['Alice', 'Bob', 'Charlie', 'Diana', 'Eve'], 'age': [12, 35, 72, 18, 65]})

def classify_age(age):
    if age < 18:
        return 'minor'
    elif age <= 65:
        return 'adult'
    else:
        return 'senior'

vfunc = np.vectorize(classify_age)
df['category'] = vfunc(df['age'])
print(df)

